import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://dev-api.example.com"
        case .staging:
            return "https://staging-api.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
}

enum NetworkError: Error {
    case invalidURL
    case noData
    case decodingError
    case serverError(Int)
    case unknown
}

struct User: Codable {
    let id: Int
    let username: String
    let email: String
    let firstName: String?
    let lastName: String?
}

struct AuthRequest: Codable {
    let username: String
    let password: String
}

struct AuthResponse: Codable {
    let token: String
    let user: User
}

class NetworkManager {
    static let shared = NetworkManager()
    
    private var environment: Environment = .production
    private var authToken: String?
    
    private init() {}
    
    func setEnvironment(_ environment: Environment) {
        self.environment = environment
    }
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    func clearAuthToken() {
        self.authToken = nil
    }
    
    func login(username: String, password: String, completion: @escaping (Result<AuthResponse, NetworkError>) -> Void) {
        let authRequest = AuthRequest(username: username, password: password)
        
        request(
            endpoint: "/auth/login",
            method: .post,
            body: authRequest,
            responseType: AuthResponse.self
        ) { result in
            if case .success(let authResponse) = result {
                self.setAuthToken(authResponse.token)
            }
            completion(result)
        }
    }
    
    func getUser(userId: Int, completion: @escaping (Result<User, NetworkError>) -> Void) {
        request(
            endpoint: "/users/\(userId)",
            method: .get,
            responseType: User.self,
            completion: completion
        )
    }
    
    func getCurrentUser(completion: @escaping (Result<User, NetworkError>) -> Void) {
        request(
            endpoint: "/users/me",
            method: .get,
            responseType: User.self,
            completion: completion
        )
    }
    
    func getUsers(completion: @escaping (Result<[User], NetworkError>) -> Void) {
        request(
            endpoint: "/users",
            method: .get,
            responseType: [User].self,
            completion: completion
        )
    }
    
    private func request<T: Decodable, U: Encodable>(
        endpoint: String,
        method: HTTPMethod,
        body: U? = nil,
        responseType: T.Type,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        guard let url = URL(string: environment.baseURL + endpoint) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            do {
                request.httpBody = try JSONEncoder().encode(body)
            } catch {
                completion(.failure(.decodingError))
                return
            }
        }
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if error != nil {
                completion(.failure(.unknown))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.unknown))
                return
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(.serverError(httpResponse.statusCode)))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let decodedResponse = try JSONDecoder().decode(T.self, from: data)
                completion(.success(decodedResponse))
            } catch {
                completion(.failure(.decodingError))
            }
        }
        
        task.resume()
    }
    
    private func request<T: Decodable>(
        endpoint: String,
        method: HTTPMethod,
        responseType: T.Type,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        request(
            endpoint: endpoint,
            method: method,
            body: Optional<String>.none,
            responseType: responseType,
            completion: completion
        )
    }
}

